function getApiBaseUrl(){const e=window.MAGALU_RUNTIME_CONFIG&&window.MAGALU_RUNTIME_CONFIG.apiBaseUrl;return e?e.replace(/\/$/,""):""}function buildApiUrl(e){const t=e.startsWith("/")?e:`/${e}`,i=getApiBaseUrl();return i?`${i}${t}`:t}function withApiDefaults(e={}){const t=new Headers(e.headers||{});return t.set("ngrok-skip-browser-warning","true"),{...e,headers:t}}async function parseApiResponse(e){if((e.headers.get("content-type")||"").includes("application/json"))return e.json();const t=await e.text();return{error:t,rawText:t}}window.magaluApi={buildApiUrl:buildApiUrl,parseApiResponse:parseApiResponse,withApiDefaults:withApiDefaults};